{{(() => {
                    const type = ReportTypeSelect.selectedOptionValue;
                    switch(type) {
                      case 'all_orders': 
                        return AllOrdersReport.data?.length || 0;
                      case 'daily_cash_flow': 
                        return DailyCashFlowReport.data?.reduce((sum, row) => sum + row.total_orders, 0) || 0;
                      case 'payment_analysis': 
                        return PaymentAnalysisReport.data?.reduce((sum, row) => sum + row.total_orders, 0) || 0;
                      case 'monthly_summary': 
                        return MonthlyFinancialSummary.data?.reduce((sum, row) => sum + row.total_orders, 0) || 0;
                      case 'business_metrics': 
                        return BusinessMetricsDashboard.data?.[0]?.total_orders || 0;
                      default: 
                        return 0;
                    }
                  })()}}
